package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;

import java.lang.reflect.Field;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testIsQuoteCharacterSet_WhenQuoteCharacterIsSet() throws Exception {
        // Use reflection to set private field quoteCharacter to a non-null value
        Field quoteCharacterField = CSVFormat.class.getDeclaredField("quoteCharacter");
        quoteCharacterField.setAccessible(true);
        quoteCharacterField.set(csvFormat, '"');

        boolean result = csvFormat.isQuoteCharacterSet();

        assertTrue(result, "Expected isQuoteCharacterSet() to return true when quoteCharacter is set");
    }

    @Test
    void testIsQuoteCharacterSet_WhenQuoteCharacterIsNull() throws Exception {
        // Use reflection to set private field quoteCharacter to null
        Field quoteCharacterField = CSVFormat.class.getDeclaredField("quoteCharacter");
        quoteCharacterField.setAccessible(true);
        quoteCharacterField.set(csvFormat, null);

        boolean result = csvFormat.isQuoteCharacterSet();

        assertFalse(result, "Expected isQuoteCharacterSet() to return false when quoteCharacter is null");
    }
}
